import (
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject for email header (prevent header injection)
	cleanedSubject := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", ""), "\n", "")
	emailSubject := "Feedback: " + cleanedSubject

	// Parse addresses to get properly formatted RFC 5322 strings (handles quoting display names)
	parsedFrom, _ := mail.ParseAddress(fromAddr) // Safe: already validated
	parsedTo, _ := mail.ParseAddress(toAddr)     // Safe: already validated

	// Escape all user-provided content for HTML safety (prevents XSS/breakage in email body)
	escapedUserName := html.EscapeString(userName)
	escapedSubjectBody := html.EscapeString(subject)        // Original subject for body display
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct RFC-compliant headers with properly formatted addresses
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		parsedFrom.String(),
		parsedTo.String(),
		emailSubject,
	)

	// Construct HTML body with escaped content (preserves whitespace in feedback via <pre>)
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    .feedback-content {
      font-family: Arial, sans-serif;
      background-color: #f9f9f9;
      padding: 10px;
      border: 1px solid #ddd;
      white-space: pre-wrap;
      word-break: break-word;
    }
  </style>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div>
    <strong>Message:</strong>
    <div class="feedback-content">%s</div>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubjectBody,
		escapedFeedbackContent,
	)

	return headers + htmlBody, nil
}

