package main

import (
	"fmt"
	"html"
	"strings"
	"time"
)

// BuildFeedbackEmail constructs a complete MIME email message containing user feedback.
// The returned string is formatted for direct use with net/smtp.SendMail.
// All user inputs are sanitized for header safety and HTML-escaped for body safety.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Sanitize header values to prevent SMTP header injection
	cleanHeader := func(s string) string {
		s = strings.ReplaceAll(s, "\r", "")
		s = strings.ReplaceAll(s, "\n", "")
		return s
	}

	fromClean := cleanHeader(fromAddr)
	toClean := cleanHeader(toAddr)
	subjectClean := cleanHeader(subject)
	if subjectClean == "" {
		subjectClean = "No Subject"
	}

	// Generate RFC 5322-compliant date header
	dateHeader := time.Now().Format(time.RFC1123Z)

	// HTML-escape user inputs to prevent XSS and rendering issues in email body
	escapedUser := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Construct responsive HTML email body with clear visual hierarchy
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif; line-height: 1.6; color: #333; max-width: 800px; margin: 20px auto; padding: 25px; border: 1px solid #e1e4e8; border-radius: 8px; background-color: #ffffff; }
    .header { border-bottom: 2px solid #0366d6; padding-bottom: 15px; margin-bottom: 25px; }
    h1 { color: #24292e; margin: 0; font-size: 28px; }
    .feedback-section { background-color: #f6f8fa; border-radius: 6px; padding: 20px; margin: 20px 0; }
    .label { font-weight: 600; color: #586069; font-size: 16px; margin: 10px 0 5px; display: block; }
    .value { font-size: 18px; color: #24292e; margin: 5px 0; word-break: break-word; }
    .content-box { background: white; border: 1px solid #d1d5da; border-radius: 6px; padding: 18px; margin-top: 8px; line-height: 1.7; white-space: pre-wrap; font-family: 'SFMono-Regular', Consolas, 'Liberation Mono', Menlo, monospace; font-size: 16px; }
    .footer { margin-top: 30px; padding-top: 15px; border-top: 1px solid #eaecef; color: #6a737d; font-size: 14px; }
    @media (max-width: 600px) {
      body { padding: 15px; margin: 10px; }
      .content-box { padding: 15px; font-size: 15px; }
    }
  </style>
</head>
<body>
  <div class="header">
    <h1>📨 New User Feedback Received</h1>
  </div>

  <div class="feedback-section">
    <span class="label">👤 Submitted By</span>
    <div class="value">%s</div>

    <span class="label">📌 Feedback Subject</span>
    <div class="value">%s</div>

    <span class="label">💬 Detailed Feedback</span>
    <div class="content-box">%s</div>
  </div>

  <div class="footer">
    <p>This feedback was submitted automatically through the user feedback system.<br>
    Please review and respond to the user at your earliest convenience.</p>
  </div>
</body>
</html>`, escapedUser, escapedSubject, escapedContent)

	// Assemble complete MIME message with required headers
	message := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nDate: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n%s",
		fromClean,
		toClean,
		subjectClean,
		dateHeader,
		htmlBody)

	return message, nil
}

func main() {
