		fmt.Sprintf("Subject: %s", subject),
		fmt.Sprintf("Date: %s", time.Now().Format(time.RFC1123Z)),
		"Content-Type: text/html; charset=UTF-8",
		"MIME-Version: 1.0",
	}
	headerBlock := strings.Join(headers, "\r\n")

	// Sanitize and format feedback content for HTML body
	cleanContent := strings.ReplaceAll(feedbackContent, "\r", "") // Normalize line endings
	escapedUserName := html.EscapeString(userName)
