package main

import (
	"fmt"
	"html"
	"log"
	"strings"
)

// BuildFeedbackEmail constructs a complete MIME email message (headers + HTML body)
// suitable for sending via net/smtp.SendMail. The email contains user-submitted
// feedback information formatted in HTML with proper escaping and SMTP-compliant line endings.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Validate required fields
	if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
		return "", fmt.Errorf("all fields are required: fromAddr, toAddr, userName, subject, feedbackContent")
	}

	// Escape user inputs to prevent HTML injection and rendering issues
	escapedUserName := html.EscapeString(userName)
	escapedFeedbackSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct HTML body with preserved whitespace formatting for feedback content
	bodyTemplate := `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<title>User Feedback</title>
	<style>
		body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; line-height: 1.5; color: #333; max-width: 800px; margin: 20px auto; padding: 0 15px; }
		.header { border-bottom: 2px solid #4CAF50; padding-bottom: 10px; margin-bottom: 25px; }
		.feedback-item { margin: 15px 0; }
		.label { font-weight: bold; color: #555; margin-right: 8px; }
		.content-box { 
			background-color: #f8f9fa; 
			border-left: 3px solid #4CAF50; 
			padding: 15px; 
			border-radius: 0 4px 4px 0;
			white-space: pre-wrap;
			line-height: 1.6;
			font-family: 'Courier New', monospace;
			margin: 10px 0;
		}
		.footer { margin-top: 30px; color: #777; font-size: 0.9em; border-top: 1px dashed #ddd; padding-top: 10px; }
	</style>
</head>
<body>
	<div class="header">
		<h1>📬 New User Feedback</h1>
	</div>

	<div class="feedback-item">
		<span class="label">👤 Username:</span>
		<span>%s</span>
	</div>

	<div class="feedback-item">
		<span class="label">📌 Feedback Subject:</span>
		<span>%s</span>
	</div>

	<div class="feedback-item">
		<span class="label">📝 Feedback Content:</span>
		<div class="content-box">%s</div>
	</div>

	<div class="footer">
		<p>This feedback was submitted through the user feedback system. Please review and respond accordingly.</p>
	</div>
</body>
</html>`

	// Generate HTML body with escaped content
	bodyHTML := fmt.Sprintf(
		bodyTemplate,
		escapedUserName,
		escapedFeedbackSubject,
		escapedFeedbackContent,
	)

	// Normalize line endings to CRLF (\r\n) for SMTP compliance:
	// 1. Remove any existing \r to handle mixed line endings
	// 2. Convert all \n to \r\n (required by RFC 5321 for SMTP messages)
	bodyHTML = strings.ReplaceAll(bodyHTML, "\r", "")
	bodyHTML = strings.ReplaceAll(bodyHTML, "\n", "\r\n")

	// Sanitize subject for email header (prevent header injection)
	safeSubject := strings.ReplaceAll(subject, "\r", "")
	safeSubject = strings.ReplaceAll(safeSubject, "\n", "")
	emailSubject := "Feedback: " + safeSubject

	// Construct RFC 5322-compliant headers with required MIME information
	headers := fmt.Sprintf(
		"From: %s\r\n"+
			"To: %s\r\n"+
			"Subject: %s\r\n"+
			"Content-Type: text/html; charset=\"UTF-8\"\r\n"+
			"MIME-Version: 1.0\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Assemble complete message: headers + blank line + body
	fullMessage := headers + "\r\n" + bodyHTML
	return fullMessage, nil
}

func main() {
	// Example usage demonstrating function output
	emailMsg, err := BuildFeedbackEmail(
		"user@client.com",
		"support@company.com",
		"Alex Rivera",
		"Checkout Button Issue",
		"I tried to complete my purchase but the checkout button does nothing when clicked.\n\nSteps to reproduce:\n1. Add item to cart\n2. Go to cart page\n3. Click 'Proceed to Checkout'\n\nExpected: Redirect to payment page\nActual: No response, console shows JS error",
	)
	if err != nil {
		log.Fatalf("Failed to build feedback email: %v", err)
	}

	// Output the complete email message (ready for smtp.SendMail)
	fmt.Println(emailMsg)
}

