// BuildFeedbackEmail constructs a complete SMTP-ready email message containing user feedback.
// The returned string includes all necessary headers and an HTML-formatted body.
// Parameters:
//   - fromAddr: Sender's email address (used in "From" header)
//   - toAddr: Recipient's email address (used in "To" header)
//   - userName: User's name (displayed in email body)
//   - subject: Feedback subject line (displayed in email body)
//   - feedbackContent: User's feedback text (displayed in email body)
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
	// Validate critical email header fields
	if fromAddr == "" {
		return "", errors.New("fromAddr cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("toAddr cannot be empty")
	}

	// Escape all user-provided content for HTML safety
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct HTML body with preserved whitespace and clear visual structure
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<title>Feedback Submission</title>
	<style>
		body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
		.container { max-width: 650px; margin: 20px auto; padding: 25px; border: 1px solid #e1e1e1; border-radius: 8px; background-color: #ffffff; }
		.header { border-bottom: 2px solid #4a90e2; padding-bottom: 15px; margin-bottom: 20px; }
		.content-box { background-color: #f8f9fa; border-left: 3px solid #4a90e2; padding: 15px; margin: 15px 0; }
		.label { font-weight: bold; color: #555; margin-top: 10px; }
		.footer { margin-top: 25px; padding-top: 15px; border-top: 1px solid #eee; font-size: 0.9em; color: #777; }
		.pre-wrap { white-space: pre-wrap; word-break: break-word; }
	</style>
</head>
<body>
	<div class="container">
		<div class="header">
			<h1>New User Feedback Received</h1>
		</div>

		<div class="label">User:</div>
		<div>%s</div>

		<div class="label">Feedback Subject:</div>
		<div>%s</div>

		<div class="label">Feedback Details:</div>
		<div class="content-box">
			<div class="pre-wrap">%s</div>
		</div>

		<div class="footer">
			<p>This feedback was submitted through the user feedback system. Please review promptly.</p>
		</div>
	</div>
</body>
</html>`, escapedUserName, escapedSubject, escapedFeedbackContent)

	// Construct RFC 5322-compliant headers with CRLF line breaks
	headers := []string{
		fmt.Sprintf("From: %s", fromAddr),
		fmt.Sprintf("To: %s", toAddr),
		"Subject: New User Feedback Submission",
		"MIME-Version: 1.0",
		"Content-Type: text/html; charset=UTF-8",
		"Content-Transfer-Encoding: quoted-printable", // Ensures safe transmission of special characters
	}

	// Combine headers and body with proper SMTP separation (double CRLF)
	fullMessage := strings.Join(headers, "\r\n") + "\r\n\r\n" + htmlBody
	return fullMessage, nil
}

func main() {
	// Example usage demonstrating function capabilities
	emailMsg, err := BuildFeedbackEmail(
		"user@example.com",
		"support@company.com",
		"Alex Rivera",
		"Feature Request: Dark Mode",
		"I'd love to see a dark mode option in the application.\n\nIt would be easier on the eyes during nighttime use, especially for developers working late. Could this be added in the next release?\n\nThanks for considering!",
	)
	if err != nil {
