import (
	"errors"
	"fmt"
	"html"
	"strings"
)

// BuildFeedbackEmail constructs a complete MIME email message (headers + HTML body)
// suitable for sending via net/smtp. Returns the full message string and any error.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Sanitize and validate critical address fields
	fromClean := strings.ReplaceAll(strings.ReplaceAll(fromAddr, "\r", ""), "\n", "")
	toClean := strings.ReplaceAll(strings.ReplaceAll(toAddr, "\r", ""), "\n", "")
	if fromClean == "" || toClean == "" {
		return "", errors.New("fromAddr and toAddr must not be empty")
	}

	// Build and sanitize email subject line (header field)
	userNameHdr := strings.ReplaceAll(strings.ReplaceAll(userName, "\r", ""), "\n", "")
	subjectHdr := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", ""), "\n", "")
	emailSubject := "Feedback from " + userNameHdr + ": " + subjectHdr
	emailSubject = strings.ReplaceAll(strings.ReplaceAll(emailSubject, "\r", ""), "\n", "")
	if emailSubject == "" {
		emailSubject = "User Feedback Received"
	}

	// Prepare HTML body content with proper escaping and formatting
	escapedUserName := html.EscapeString(userName)
	escapedFeedbackSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent) // Preserves \n for pre-wrap rendering

	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<title>User Feedback</title>
	<style>
		body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 800px; margin: 20px auto; }
		.header { border-bottom: 2px solid #4a90e2; padding-bottom: 10px; margin-bottom: 20px; }
		.section { margin: 15px 0; }
		.label { font-weight: bold; color: #555; margin-right: 5px; }
		.content-box { 
			background-color: #f8f9fa; 
			border-left: 4px solid #4a90e2; 
			padding: 15px; 
			white-space: pre-wrap; 
			border-radius: 0 4px 4px 0;
			font-family: monospace;
			margin-top: 8px;
		}
		.footer { margin-top: 25px; color: #777; font-size: 0.9em; border-top: 1px dashed #ccc; padding-top: 10px; }
	</style>
</head>
<body>
	<div class="header">
		<h1>🆕 New User Feedback</h1>
	</div>

	<div class="section">
		<span class="label">👤 Username:</span><span>%s</span>
	</div>

	<div class="section">
		<span class="label">📌 Feedback Subject:</span><span>%s</span>
	</div>

	<div class="section">
		<div class="label">📝 Feedback Content:</div>
		<div class="content-box">%s</div>
	</div>

	<div class="footer">
		<p>This feedback was submitted through the user feedback system. Please review and respond accordingly.</p>
	</div>
</body>
</html>`, escapedUserName, escapedFeedbackSubject, escapedFeedbackContent)

	// Assemble full MIME message with proper CRLF line breaks
	headers := []string{
		"From: " + fromClean,
		"To: " + toClean,
		"Subject: " + emailSubject,
		"Content-Type: text/html; charset=utf-8",
		"MIME-Version: 1.0",
		"X-Mailer: Go Feedback System",
	}

	fullMessage := strings.Join(headers, "\r\n") + "\r\n\r\n" + htmlContent
	return fullMessage, nil
}

