)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate and parse email addresses to ensure proper RFC 5322 formatting
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject for email header: remove CR/LF to prevent header injection
	sanitizedSubject := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", ""), "\n", "")
	emailSubject := "Feedback: " + sanitizedSubject

	// Escape user-provided content for HTML safety (prevents XSS and preserves literal content)
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Construct RFC 5322-compliant headers using properly formatted addresses
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromParsed.String(),
		toParsed.String(),
		emailSubject,
	)

	// Construct HTML body with escaped content; <pre> preserves whitespace in feedback
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 800px; margin: 20px auto; }
    .feedback-container { background-color: #f8f9fa; border-left: 4px solid #0d6efd; padding: 15px; margin: 15px 0; }
    pre { white-space: pre-wrap; word-break: break-word; margin: 10px 0; }
  </style>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div class="feedback-container">
    <strong>Message:</strong>
    <pre>%s</pre>
  </div>
  <hr>
  <small>This feedback was submitted through our user portal. Please respond promptly.</small>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	return headers + htmlBody, nil
}

