	}

	// Sanitize subject for email header to prevent CRLF injection attacks
	// Replace CR/LF characters with space and trim extraneous whitespace
	subjectForHeader := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", " "), "\n", " ")
