package main

import (
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate and parse email addresses to ensure proper RFC 5322 formatting
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject for email header (remove newlines to prevent header injection and RFC violations)
	cleanedSubject := strings.ReplaceAll(strings.ReplaceAll(subject, "\r", " "), "\n", " ")
	emailSubject := fmt.Sprintf("Feedback: %s", cleanedSubject)

	// Escape all user-provided content for HTML safety (prevents XSS and preserves content integrity)
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Construct RFC 5322-compliant headers using properly formatted addresses
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromParsed.String(),
		toParsed.String(),
		emailSubject,
	)

	// Construct HTML body with escaped content (preserves whitespace in feedback via <pre>)
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 800px; margin: 20px auto; }
    .feedback-container { background-color: #f8f9fa; border-left: 4px solid #0d6efd; padding: 15px; margin: 15px 0; }
    .label { font-weight: bold; color: #495057; margin-top: 8px; }
    pre { 
      background-color: #ffffff; 
      border: 1px solid #dee2e6; 
      border-radius: 4px; 
      padding: 12px; 
      margin: 8px 0; 
      white-space: pre-wrap; 
      word-break: break-word; 
      font-family: Consolas, monospace; 
      font-size: 14px; 
      overflow-x: auto; 
    }
    h2 { color: #0d6efd; border-bottom: 2px solid #e9ecef; padding-bottom: 8px; }
  </style>
</head>
<body>
  <h2>User Feedback Received</h2>
  <div class="feedback-container">
    <div class="label">Submitted by:</div>
    <div>%s</div>

    <div class="label">Subject:</div>
    <div>%s</div>

    <div class="label">Message:</div>
    <pre>%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedback,
	)

	return headers + htmlBody, nil
}

