// BuildFeedbackEmail constructs a complete MIME email message (headers + HTML body)
// suitable for sending via net/smtp.SendMail. Returns the full RFC-compliant message string.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
    // Sanitize email addresses to prevent header injection
    sanitizedFrom := strings.ReplaceAll(strings.ReplaceAll(fromAddr, "\r", ""), "\n", "")
    sanitizedTo := strings.ReplaceAll(strings.ReplaceAll(toAddr, "\r", ""), "\n", "")

    if sanitizedFrom == "" {
        return "", errors.New("fromAddr cannot be empty")
    }
    if sanitizedTo == "" {
        return "", errors.New("toAddr cannot be empty")
    }

    // Construct and sanitize email subject line
    emailSubject := "Feedback from " + userName + ": " + subject
    sanitizedSubject := strings.ReplaceAll(strings.ReplaceAll(emailSubject, "\r", ""), "\n", "")
    if sanitizedSubject == "" {
        sanitizedSubject = "User Feedback"
    }

    // Escape all user inputs for HTML safety
    escapedUserName := html.EscapeString(userName)
    escapedSubject := html.EscapeString(subject)
    escapedContent := html.EscapeString(feedbackContent)

    // Build HTML body with preserved formatting
    htmlBody := `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        .feedback-container { font-family: Arial, sans-serif; max-width: 800px; margin: 20px; }
        .header { border-bottom: 2px solid #4CAF50; padding-bottom: 10px; margin-bottom: 20px; }
        .field { margin: 15px 0; line-height: 1.5; }
        .label { font-weight: bold; color: #333; }
        .content-box { 
            background-color: #f9f9f9; 
            border-left: 4px solid #4CAF50; 
            padding: 15px; 
            white-space: pre-wrap; 
            font-family: monospace;
            margin-top: 5px;
        }
    </style>
</head>
<body>
    <div class="feedback-container">
        <div class="header">
            <h1>📝 New User Feedback</h1>
        </div>

        <div class="field">
            <span class="label">👤 Username:</span><br>
            ` + escapedUserName + `
        </div>

        <div class="field">
            <span class="label">📌 Feedback Subject:</span><br>
            ` + escapedSubject + `
        </div>

        <div class="field">
            <span class="label">💬 Feedback Content:</span>
            <div class="content-box">` + escapedContent + `</div>
        </div>

        <div style="margin-top: 30px; color: #777; font-size: 0.9em;">
            <p>This feedback was submitted through the user feedback system.</p>
        </div>
    </div>
</body>
</html>`

    // Construct RFC-compliant headers with proper line breaks
    headers := "From: " + sanitizedFrom + "\r\n" +
        "To: " + sanitizedTo + "\r\n" +
        "Subject: " + sanitizedSubject + "\r\n" +
        "Content-Type: text/html; charset=UTF-8\r\n" +
        "MIME-Version: 1.0"

    // Combine headers and body with required separator
    return headers + "\r\n\r\n" + htmlBody, nil
}

func main() {
    // Example usage demonstrating function capabilities
    emailMsg, err := BuildFeedbackEmail(
        "user@example.com",
        "support@company.com",
        "Jane Developer",
        "Login Issue",
        "I encountered an error when trying to log in:\n\n"+
            "1. Entered valid credentials\n"+
            "2. Clicked 'Sign In'\n"+
            "3. Received 'Invalid token' error\n\n"+
            "Expected: Successful login\n"+
            "Browser: Chrome 124.0.6367.78",
    )

    if err != nil {
        fmt.Printf("❌ Email generation failed: %v\n", err)
        return
    }

    // Output the complete email message (ready for smtp.SendMail)
    fmt.Println("✅ Generated email message:")
    fmt.Println(strings.Repeat("=", 70))
    fmt.Println(emailMsg)
    fmt.Println(strings.Repeat("=", 70))
    fmt.Println("\n💡 This message can be directly passed to net/smtp.SendMail")
}

