// BuildFeedbackEmail constructs a complete MIME email message with HTML body
// containing user feedback details. The returned string is formatted for direct
// use with net/smtp.SendMail. All user inputs are sanitized to prevent header
// injection and XSS vulnerabilities.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (string, error) {
    // Sanitize header values: remove CR/LF to prevent header injection
    sanitizeHeader := func(s string) string {
        return strings.ReplaceAll(strings.ReplaceAll(s, "\r", ""), "\n", "")
    }

    safeUserName := sanitizeHeader(userName)
    safeSubjectHdr := sanitizeHeader(subject)
    safeFromAddr := sanitizeHeader(fromAddr)
    safeToAddr := sanitizeHeader(toAddr)

    // Construct From header with display name (RFC 5322 compliant quoting)
    var fromHeader string
    if safeUserName != "" {
        // Escape double quotes in display name
        quotedName := strings.ReplaceAll(safeUserName, `"`, `\"`)
        fromHeader = `"` + quotedName + `" <` + safeFromAddr + `>`
    } else {
        fromHeader = safeFromAddr
    }

    // Build informative email subject line
    emailSubject := "Feedback"
    if safeUserName != "" {
        emailSubject += " from " + safeUserName
    }
    if safeSubjectHdr != "" {
        if safeUserName != "" {
            emailSubject += ": "
        }
        emailSubject += safeSubjectHdr
    }
    emailSubject = sanitizeHeader(emailSubject)

    // Prepare email headers
    headers := []string{
        "From: " + fromHeader,
        "To: " + safeToAddr,
        "Subject: " + emailSubject,
        `Content-Type: text/html; charset="UTF-8"`,
        "MIME-Version: 1.0",
    }

    // Escape HTML content to prevent XSS
    userNameEscaped := html.EscapeString(userName)
    subjectEscaped := html.EscapeString(subject)

    // Process feedback content: escape HTML, normalize line endings, convert to <br>
    contentEscaped := html.EscapeString(feedbackContent)
    contentNormalized := strings.ReplaceAll(strings.ReplaceAll(contentEscaped, "\r\n", "\n"), "\r", "\n")
    contentWithBreaks := strings.ReplaceAll(contentNormalized, "\n", "<br>")

    // Construct HTML email body
    htmlBody := `<!DOCTYPE html>
<html>
<head>
  <meta http-equiv="Content-Type" content="text/html; charset=utf-8">
  <title>User Feedback</title>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 600px; margin: 20px; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
    h2 { color: #2c3e50; border-bottom: 2px solid #3498db; padding-bottom: 10px; }
    .field { margin: 15px 0; }
    .label { font-weight: bold; color: #2980b9; }
    .content { margin-top: 5px; padding: 10px; background-color: #f8f9fa; border-left: 3px solid #3498db; }
  </style>
</head>
<body>
  <div class="container">
    <h2>New User Feedback Received</h2>

    <div class="field">
      <div class="label">Username:</div>
      <div class="content">` + userNameEscaped + `</div>
    </div>

    <div class="field">
      <div class="label">Feedback Subject:</div>
      <div class="content">` + subjectEscaped + `</div>
    </div>

    <div class="field">
      <div class="label">Feedback Content:</div>
      <div class="content">` + contentWithBreaks + `</div>
    </div>

    <div style="margin-top: 25px; padding-top: 15px; border-top: 1px solid #eee; color: #7f8c8d; font-size: 0.9em;">
      This feedback was submitted through the user feedback system.
    </div>
  </div>
</body>
</html>`

    // Combine headers and body with SMTP-required CRLF line breaks
    message := strings.Join(headers, "\r\n") + "\r\n\r\n" + htmlBody
    return message, nil
}

