	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject for email header to prevent header injection
	// Replace CR/LF with space to maintain single-line header requirement
	cleanSubjectHeader := strings.ReplaceAll(subject, "\r", " ")
	cleanSubjectHeader = strings.ReplaceAll(cleanSubjectHeader, "\n", " ")
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubjectHeader)

	// Escape all user-provided content for HTML safety
	escUserName := html.EscapeString(userName)
	escSubjectBody := html.EscapeString(subject)
